import { test, expect } from '../../support/fixtures/routeShyftStory26.fixture';
import { login } from '../../helpers/auth';

test.describe('Story 2-6 Canonical Timezone Processing Across Intake and Scheduling (ATDD E2E RED)', () => {
  test.skip('[P1] scheduling UI renders localized time values with visible timezone source indicator @P1', async ({ page, story26Context }) => {
    await login(page);

    const loadResponse = page.waitForResponse(
      (response) => response.url().includes(story26Context.paths.resourceCollection) && response.request().method() === 'GET',
    );

    await page.goto(story26Context.paths.ui + '?tenantId=' + story26Context.tenantId + '&orgUnitId=' + story26Context.orgUnitId);
    await loadResponse;

    await expect(page.getByRole('heading', { name: 'Scheduling' })).toBeVisible();
    await expect(page.getByTestId('routeshyft-scheduling-local-time')).toBeVisible();
    await expect(page.getByTestId('routeshyft-timezone-source-badge')).toBeVisible();
  });

  test.skip('[P1] scheduling UI never renders raw UTC values and shows deterministic fallback guidance @P1', async ({ page, story26Context }) => {
    await login(page);

    const submitResponse = page.waitForResponse(
      (response) => response.url().includes(story26Context.paths.resourceCollection) && response.request().method() === 'POST',
    );

    await page.goto(story26Context.paths.ui + '?tenantId=' + story26Context.tenantId + '&orgUnitId=' + story26Context.orgUnitId);
    await page.getByRole('button', { name: 'Save Schedule' }).click();
    await submitResponse;

    await expect(page.getByTestId('routeshyft-timezone-warning-banner')).toBeVisible();
    await expect(page.getByTestId('routeshyft-timezone-refusal-code')).toHaveText(story26Context.refusalCode);
    await expect(page.getByTestId('routeshyft-timezone-next-steps')).toBeVisible();
  });
});
